# Backwards-compatible aliases and feature flags
PEP_560 = True
GenericMeta = type
_PEP_696_IMPLEMENTED = sys.version_info >= (3, 13)
# Check whether ForwardRef supports the "__forward_is_class__" attribute.
_FORWARD_REF_HAS_CLASS = (
    hasattr(typing.ForwardRef, "__forward_is_class__")
    or "__forward_is_class__" in getattr(typing.ForwardRef, "__slots__", ())
)


class _Sentinel:
    def __repr__(self):
        return "<sentinel>"


_marker = _Sentinel()

# Build a tuple of available alias types to use in isinstance checks.
_alias_types = tuple(
    t
    for t in (
        getattr(typing, "_GenericAlias", None),
        getattr(_types, "GenericAlias", None),
        getattr(_types, "UnionType", None),
    )
    if isinstance(t, type)
)


def _should_collect_from_parameters(tp):
    """Return True if 'tp' is an instance of a known generic/union alias type."""
    if not _alias_types:
        return False
    return isinstance(tp, _alias_types)


NoReturn = typing.NoReturn

# Common unconstrained type variables used by container types.
T = typing.TypeVar("T")
KT = typing.TypeVar("KT")
VT = typing.TypeVar("VT")
T_co = typing.TypeVar("T_co", covariant=True)
T_contra = typing.TypeVar("T_contra", contravariant=True)